const trades = $('Fetch Today Trades').all().map(i => i.json);
const rejected = $('Fetch Today Rejections').all().map(i => i.json);
const wins = trades.filter(t => t.win);
const pnls = trades.map(t => parseFloat(t.option_pnl_pct||0));
const avg = pnls.length ? (pnls.reduce((a,b)=>a+b,0)/pnls.length).toFixed(1) : null;
const best = pnls.length ? Math.max(...pnls).toFixed(1) : null;
const worst = pnls.length ? Math.min(...pnls).toFixed(1) : null;
const watchFails = rejected.filter(r => (r.last_error||'').includes('watch_arm_failed'));
return [{ json: {
  date: new Date().toLocaleDateString('en-US',{weekday:'long',month:'long',day:'numeric'}),
  trades_total: trades.length,
  wins: wins.length,
  losses: trades.length - wins.length,
  win_rate: trades.length ? Math.round(wins.length/trades.length*100) : 0,
  avg_pnl: avg,
  best_trade: best,
  worst_trade: worst,
  rejections: rejected.length,
  watch_failures: watchFails.length,
  trade_details: trades.map(t => `${t.ticker} ${t.side}: ${parseFloat(t.option_pnl_pct||0) >= 0 ? '+' : ''}${parseFloat(t.option_pnl_pct||0).toFixed(1)}% (${t.exit_reason||'auto'})`).join('\n')
}}];

const resp = $json;
const raw = resp.content[0].text;
let parsed; try { parsed = JSON.parse(raw); } catch(e) { parsed = {}; }
const stats = $('Build EOD Summary').first().json;
return [{ json: { ...parsed, ...stats } }];
